def test_generate_with_invalid_image_id(client: TestClient) -> None:
    """Should reject generation request when image id is unknown."""
    response = client.post(
        "/generate-video",
        json={
            "image_id": "img_does_not_exist",
            "prompt": "Simple pan motion",
            "duration_seconds": 4,
            "aspect_ratio": "1:1",
        },
    )

    assert response.status_code == 400
